var idx = lunr(function () {
    this.ref('id')
    this.field('title')
    this.field('body')

    documents.forEach(function (doc) {
        this.add(doc)
    }, this)
});
function lunr_search(term) {
    var el = document.getElementById('lunrsearchresults');
    var ul = document.createElement('ul');
    el.textContent = '';

    if(term) {
        el.classList.add('visible');
        var heading = document.createElement('p');
        heading.style.fontWeight = '600';
        heading.style.marginBottom = '8px';
        heading.textContent = "Results for '" + term + "'";
        el.appendChild(heading);
        el.appendChild(ul);

        var results = idx.search(term);
        if(results.length > 0){
            for (var i = 0; i < results.length; i++) {
                var ref = results[i]['ref'];
                var url = documents[ref]['url'];
                var title = documents[ref]['title'];
                var body = documents[ref]['body'].substring(0, 160) + '...';

                var li = document.createElement('li');
                li.className = 'lunrsearchresult';
                var a = document.createElement('a');
                a.href = url;
                var titleSpan = document.createElement('span');
                titleSpan.className = 'title';
                titleSpan.textContent = title;
                var br = document.createElement('br');
                var bodySmall = document.createElement('small');
                var bodySpan = document.createElement('span');
                bodySpan.className = 'body';
                bodySpan.textContent = body;
                bodySmall.appendChild(bodySpan);
                a.appendChild(titleSpan);
                a.appendChild(br);
                a.appendChild(bodySmall);
                li.appendChild(a);
                ul.appendChild(li);
            }
        } else {
            var li = document.createElement('li');
            li.className = 'lunrsearchresult';
            li.textContent = 'No results found.';
            ul.appendChild(li);
        }
    } else {
        el.classList.remove('visible');
    }
    return false;
}

$(function() {
    $(document).on('click', function(e) {
        if (!$(e.target).closest('#lunrsearchresults, .nav-search').length) {
            $('#lunrsearchresults').removeClass('visible');
        }
    });
});